import { createSlice } from "@reduxjs/toolkit";
import { configureStore } from "@reduxjs/toolkit";
import { persistStore, persistReducer } from 'redux-persist';
import storage from 'redux-persist/lib/storage'; // defaults to localStorage for web
import { combineReducers } from "redux";

const initialState={
    user:[{id:1,name:'abir'}],
    logged:[{id:1,name:'Anekha'}],
    train:[

    {id:1,name:'Parabot Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:2,name:'Dhumketu Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur'],total_seat:30,boookd_ticket:[]},
